function Invoke-Git {
    param([Parameter(Mandatory=$true)][string]$Cwd, [Parameter(Mandatory=$true)][string[]]$GitArgs)
    $previousErrorActionPreference = $ErrorActionPreference
    $output = @()
    $exitCode = $null
    try {
        $ErrorActionPreference = 'Continue'
        $output = & git -C $Cwd @GitArgs 2>&1
        $exitCode = $LASTEXITCODE
    }
    finally {
        $ErrorActionPreference = $previousErrorActionPreference
    }
    if ($exitCode -ne 0) {
        throw "git $($GitArgs -join ' ') failed with exit code $exitCode`n$output"
    }
    return $output
}

function Invoke-NativeCommand {
    param(
        [Parameter(Mandatory=$true)][string]$FilePath,
        [Parameter(Mandatory=$true)][string[]]$Arguments,
        [Parameter(Mandatory=$true)][string]$Description
    )
    $previousErrorActionPreference = $ErrorActionPreference
    $output = @()
    $exitCode = $null
    try {
        $ErrorActionPreference = 'Continue'
        $output = & $FilePath @Arguments 2>&1
        $exitCode = $LASTEXITCODE
    }
    finally {
        $ErrorActionPreference = $previousErrorActionPreference
    }
    if ($exitCode -ne 0) {
        throw "$Description failed with exit code $exitCode`n$output"
    }
    return $output
}

function Get-GitText {
    param([Parameter(Mandatory=$true)][string]$Cwd, [Parameter(Mandatory=$true)][string[]]$GitArgs)
    $output = Invoke-Git -Cwd $Cwd -GitArgs $GitArgs
    return (($output | Out-String).Trim())
}

function Get-TrackedBlob {
    param([Parameter(Mandatory=$true)][string]$Cwd, [Parameter(Mandatory=$true)][string]$Path)
    $line = Get-GitText -Cwd $Cwd -GitArgs @('ls-files','-s','--',$Path)
    if ([string]::IsNullOrWhiteSpace($line)) { return '' }
    return (($line -split '\s+')[1])
}

function Get-Sha256File {
    param([Parameter(Mandatory=$true)][string]$Path)
    $sha = [System.Security.Cryptography.SHA256]::Create()
    try {
        $bytes = [System.IO.File]::ReadAllBytes($Path)
        $hash = $sha.ComputeHash($bytes)
        return ([BitConverter]::ToString($hash) -replace '-', '').ToLowerInvariant()
    }
    finally {
        $sha.Dispose()
    }
}

function Get-RequiredGitToken {
    $candidates = @('DCOIR_GITHUB_FG_TOKEN','DCOIR_GITHUB_CL_TOKEN')
    foreach ($name in $candidates) {
        $value = [Environment]::GetEnvironmentVariable($name, 'Process')
        if ([string]::IsNullOrWhiteSpace($value)) { $value = [Environment]::GetEnvironmentVariable($name, 'Machine') }
        if (-not [string]::IsNullOrWhiteSpace($value)) {
            Write-Host "Using bridged GitHub token secret for PR branch push: $name"
            Write-Host "::add-mask::$value"
            return $value
        }
    }
    throw 'No bridged GitHub token secret is available for PR branch push. Refusing to push with the default workflow token because it may not trigger downstream checks.'
}

function Get-RepoFullName {
