    return $repoFull
}

function Get-GitHubActionsRunsForHead {
    param(
        [Parameter(Mandatory=$true)][string]$Token,
        [Parameter(Mandatory=$true)][string]$HeadSha
    )
    $repoFull = Get-RepoFullName
    $headers = @{
        Authorization = "Bearer $Token"
        Accept = 'application/vnd.github+json'
        'X-GitHub-Api-Version' = '2022-11-28'
        'User-Agent' = 'dcoir-chatgpt-exec-pr271'
    }
    $uri = "https://api.github.com/repos/$repoFull/actions/runs?head_sha=$HeadSha&per_page=20"
    return Invoke-RestMethod -Method Get -Uri $uri -Headers $headers
}

function Wait-GitHubActionsRunsForHead {
    param(
        [Parameter(Mandatory=$true)][string]$Token,
        [Parameter(Mandatory=$true)][string]$HeadSha,
        [int]$TimeoutSeconds = 180,
        [int]$PollSeconds = 15
    )
    $deadline = (Get-Date).ToUniversalTime().AddSeconds($TimeoutSeconds)
    do {
        $runs = Get-GitHubActionsRunsForHead -Token $Token -HeadSha $HeadSha
        if ($null -ne $runs -and $runs.total_count -gt 0) {
            return $runs
        }
        Start-Sleep -Seconds $PollSeconds
    } while ((Get-Date).ToUniversalTime() -lt $deadline)
    return $null
}

function Get-RequiredDownloadsDir {
