function Invoke-GitPushWithToken {
    param(
        [Parameter(Mandatory=$true)][string]$Cwd,
        [Parameter(Mandatory=$true)][string]$Token,
        [Parameter(Mandatory=$true)][string]$Refspec
    )
    $repoFull = Get-RepoFullName
