catch {
    if (-not $failureSummaryWritten -and -not [string]::IsNullOrWhiteSpace($newHead)) {
        $failureStatus = 'commit_created_push_not_confirmed'
        if ($pushCompleted) {
            $failureStatus = 'partial_mutation_push_returned_before_final_readback'
        }
        try {
            Write-ExecutionSummary -DownloadsDir $downloads -Status $failureStatus -ObservedRunSummary $observedRunSummary
        } catch {
            Write-Warning "Failure summary write also failed: $($_.Exception.Message)"
        }
    }
    throw
}
finally {
    try {
        if (Test-Path -LiteralPath $worktree) {
            Invoke-Git -Cwd $repo -GitArgs @('worktree','remove','--force',$worktree) | Out-Null
        }
    } catch {
        Write-Warning "Temporary worktree cleanup failed: $($_.Exception.Message)"
    }
}
